   114→function ScoreBadge({ score }: { score: number }) {
   115→  if (score >= 68) return <span className="text-[10px] font-bold px-1.5 py-0.5 rounded-full bg-red-500/15 text-red-400">🔥 Hot</span>;
   116→  if (score >= 38) return <span className="text-[10px] font-bold px-1.5 py-0.5 rounded-full bg-orange-400/15 text-orange-400">🌡️ Warm</span>;
   117→  return <span className="text-[10px] font-bold px-1.5 py-0.5 rounded-full bg-blue-400/15 text-blue-400">❄️ Cold</span>;
