};

function normalizeStage(s: string): LeadStage {
  const map: Record<string, LeadStage> = {
    new: "nuevo", nuevo: "nuevo",
    contacted: "contactado", contactado: "contactado",
    qualified: "calificado", calificado: "calificado",
