   143→  if (results.length < 3) {
   144→    const patC =
   145→      /"((?:[^"\\]|\\.){3,80}?)",null,\["((?:[^"\\]|\\.){5,120}?)"\]/g;
   146→    while ((m = patC.exec(html)) !== null && results.length < maxResults) {
   147→      const name = decodeUnicode(m[1]).trim();
   148→      const addr = decodeUnicode(m[2]).trim();
   149→      if (!name || seen.has(name.toLowerCase())) continue;
   150→      // Filtrar falsos positivos: la dirección debe tener aspecto de dirección
   151→      if (!/\d|calle|av\.|ruta|barrio|km/i.test(addr) && addr.length < 10) continue;
   152→      seen.add(name.toLowerCase());
   153→
   154→      results.push({
   155→        id: `gm_c_${results.length}`,
   156→        name,
   157→        address: addr,
   158→        phone: "",
   159→        website: "",
   160→        rating: 0,
   161→        reviews: 0,
   162→        status: "OPERATIONAL",
   163→        source: "google",
   164→      });
   165→    }
   166→  }
   167→
   168→  return results;
   169→}
