   171→async function searchGoogleMapsInternal(
   172→  query: string,
   173→  location: string,
   174→  maxResults: number
   175→): Promise<PlaceResult[]> {
   176→  const geo = await geocodeLocation(location);
   177→  const coordPart =
   178→    geo
   179→      ? `/@${parseFloat(geo.lat).toFixed(6)},${parseFloat(geo.lon).toFixed(6)},14z`
   180→      : "";
   181→  const searchTerm = encodeURIComponent(`${query} ${location} Argentina`);
   182→  const url = `https://www.google.com/maps/search/${searchTerm}${coordPart}`;
   183→
   184→  const resp = await fetch(url, {
   185→    headers: GMAPS_HEADERS,
   186→    signal: AbortSignal.timeout(14000),
   187→    redirect: "follow",
   188→  });
   189→
   190→  if (!resp.ok) throw new Error(`Google Maps HTTP ${resp.status}`);
   191→
   192→  // Google puede redirigir a /sorry/ (captcha) o /search?q=... (mobile)
   193→  const finalUrl = resp.url;
   194→  if (finalUrl.includes("/sorry/") || finalUrl.includes("accounts.google.com")) {
   195→    throw new Error("Google bloqueó la petición (captcha). Usando OSM como fallback.");
   196→  }
   197→
   198→  const html = await resp.text();
   199→
   200→  // Verificar que la respuesta contiene datos de Maps (no página de error)
   201→  if (!html.includes("APP_INITIALIZATION_STATE") && !html.includes("window.google")) {
   202→    throw new Error("Respuesta inesperada de Google Maps. Usando OSM como fallback.");
   203→  }
   204→
   205→  const results = extractStringArray(html, maxResults);
   206→  if (results.length === 0) {
   207→    throw new Error("No se encontraron resultados en la respuesta de Google Maps.");
   208→  }
   209→
   210→  return results;
   211→}
