   232→    [["heladeria", "helados"], '["shop"="ice_cream"]'],
   233→    [["ferreteria", "corralon"], '["shop"="hardware"]'],
   234→    [["peluqueria", "barberia"], '["shop"~"hairdresser|barber"]'],
   235→    [["inmobiliaria", "real estate"], '["shop"="estate_agent"]'],
   236→    [["kiosco", "kiosko"], '["shop"="kiosk"]'],
   237→    [["veterinaria", "veterinario"], '["amenity"="veterinary"]'],
   238→    [["dentista", "odontologia"], '["amenity"="dentist"]'],
   239→    [["clinica", "medico", "salud"], '["amenity"~"clinic|doctors|hospital"]'],
   240→    [["optica"], '["shop"="optician"]'],
   241→    [["gym", "gimnasio", "fitness"], '["leisure"~"fitness_centre|gym"]'],
   242→    [["libreria", "papeleria"], '["shop"~"books|stationery"]'],
   243→    [["ropa", "indumentaria", "boutique"], '["shop"~"clothes|fashion"]'],
   244→    [["zapateria", "calzado"], '["shop"="shoes"]'],
   245→    [["electronica", "computacion"], '["shop"~"electronics|computers"]'],
   246→    [["lavadero", "lavanderia", "tintoreria"], '["shop"~"laundry|dry_cleaning"]'],
   247→    [["notaria", "escribania", "estudio juridico"], '["office"~"lawyer|notary"]'],
   248→    [["contador", "contaduria", "estudio contable"], '["office"="accountant"]'],
   249→    [["agencia de viajes", "turismo"], '["shop"="travel_agency"]'],
   250→    [["autopartes", "repuesto"], '["shop"="car_parts"]'],
   251→    [["concesionaria", "automotriz"], '["shop"~"car|motorcycle"]'],
   252→    [["fruteria", "verduleria"], '["shop"~"greengrocer|fruits"]'],
   253→    [["carniceria", "carnicero"], '["shop"="butcher"]'],
   254→    [["pintureria"], '["shop"="paint"]'],
   255→    [["cerrajeria", "cerrajero"], '["shop"="locksmith"]'],
   256→    [["gasolinera", "nafta", "combustible", "ypf", "shell", "axion"], '["amenity"="fuel"]'],
   257→    [["estacionamiento", "playa de estacionamiento"], '["amenity"="parking"]'],
   258→    [["escuela", "colegio"], '["amenity"~"school|kindergarten"]'],
   259→    [["universidad", "instituto"], '["amenity"~"university|college"]'],
   260→    [["iglesia", "templo"], '["amenity"~"place_of_worship"]'],
   261→    [["supermercado chino", "chino"], '["shop"="supermarket"]'],
   262→  ];
   263→
   264→  for (const [keys, tag] of mapping) {
   265→    if (keys.some(k => q.includes(k))) {
   266→      return [tag];
   267→    }
   268→  }
   269→
   270→  const safe = query.replace(/['"]/g, "").trim();
   271→  return [`["name"~"${safe}",i]`];
   272→}
