   274→function buildAddress(tags: Record<string, string>): string {
   275→  const parts: string[] = [];
   276→  if (tags["addr:street"]) {
   277→    parts.push(tags["addr:street"] + (tags["addr:housenumber"] ? " " + tags["addr:housenumber"] : ""));
   278→  }
   279→  if (tags["addr:city"]) parts.push(tags["addr:city"]);
   280→  if (tags["addr:state"]) parts.push(tags["addr:state"]);
   281→  return parts.join(", ") || tags["addr:full"] || "";
   282→}
