   284→async function searchOpenStreetMap(
   285→  query: string,
   286→  location: string,
   287→  maxResults: number
   288→): Promise<PlaceResult[]> {
   289→  const geo = await geocodeLocation(location);
   290→  if (!geo) {
   291→    throw new Error(
   292→      `No se encontró la ubicación "${location}". Probá con el nombre completo de la ciudad, ej: "Neuquén Capital", "Rosario", "Córdoba".`
   293→    );
   294→  }
   295→
   296→  const { lat, lon } = geo;
   297→  const radius = 8000;
   298→  const tags = mapQueryToOSMTags(query);
   299→
   300→  const nodeLines = tags.map(t => `  node${t}(around:${radius},${lat},${lon});`).join("\n");
   301→  const wayLines  = tags.map(t => `  way${t}(around:${radius},${lat},${lon});`).join("\n");
   302→  const oql = `[out:json][timeout:30];\n(\n${nodeLines}\n${wayLines}\n);\nout body;`;
   303→
   304→  const resp = await fetch("https://overpass-api.de/api/interpreter", {
   305→    method: "POST",
   306→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
   307→    body: `data=${encodeURIComponent(oql)}`,
   308→    signal: AbortSignal.timeout(35000),
   309→  });
   310→
   311→  if (!resp.ok) {
   312→    throw new Error(
   313→      `El servicio de mapas respondió con un error (${resp.status}). Intentá de nuevo en unos segundos.`
   314→    );
   315→  }
   316→
   317→  const data = (await resp.json()) as {
   318→    elements: Array<{
   319→      id: number;
   320→      type: string;
   321→      tags?: Record<string, string>;
   322→    }>;
   323→  };
   324→
   325→  const seen = new Set<string>();
   326→  const results: PlaceResult[] = [];
   327→
   328→  for (const el of data.elements) {
   329→    const tags = el.tags ?? {};
   330→    const name = tags.name || tags["name:es"] || "";
   331→    if (!name) continue;
   332→
   333→    const key = name.toLowerCase().trim();
   334→    if (seen.has(key)) continue;
   335→    seen.add(key);
   336→
   337→    const phone = tags.phone || tags["contact:phone"] || tags["phone:mobile"] || "";
   338→    const rawWeb = tags.website || tags["contact:website"] || tags["url"] || "";
   339→    const website = rawWeb
   340→      ? rawWeb.startsWith("http") ? rawWeb : "https://" + rawWeb
   341→      : "";
   342→
   343→    results.push({
   344→      id: `osm_${el.type}_${el.id}`,
   345→      name,
   346→      address: buildAddress(tags),
   347→      phone,
   348→      website,
   349→      rating: 0,
   350→      reviews: 0,
   351→      status: "OPERATIONAL",
   352→      source: "openstreetmap",
   353→    });
   354→
   355→    if (results.length >= maxResults) break;
   356→  }
   357→
   358→  return results;
   359→}
