   361→/* ─────────────────────────────────────────────────────────────
   362→   Google Places API oficial
   363→   Requiere API key propia — datos más ricos y estables
   364→   ───────────────────────────────────────────────────────────── */
   365→
   366→async function searchGooglePlaces(
   367→  query: string,
   368→  location: string,
   369→  maxResults: number,
   370→  apiKey: string
   371→): Promise<PlaceResult[]> {
   372→  const url = "https://places.googleapis.com/v1/places:searchText";
   373→  const body = {
   374→    textQuery: `${query} en ${location}`,
   375→    maxResultCount: Math.min(maxResults, 20),
   376→    languageCode: "es",
   377→  };
   378→
   379→  const resp = await fetch(url, {
   380→    method: "POST",
   381→    headers: {
   382→      "Content-Type": "application/json",
   383→      "X-Goog-Api-Key": apiKey,
   384→      "X-Goog-FieldMask":
   385→        "places.id,places.displayName,places.formattedAddress,places.nationalPhoneNumber," +
   386→        "places.websiteUri,places.rating,places.userRatingCount,places.businessStatus",
   387→    },
   388→    body: JSON.stringify(body),
   389→    signal: AbortSignal.timeout(10000),
   390→  });
   391→
   392→  if (!resp.ok) {
   393→    const text = await resp.text();
   394→    throw new Error(`Google Places API error ${resp.status}: ${text}`);
   395→  }
   396→
   397→  const data = (await resp.json()) as {
   398→    places?: {
   399→      id?: string;
   400→      displayName?: { text?: string };
   401→      formattedAddress?: string;
   402→      nationalPhoneNumber?: string;
   403→      websiteUri?: string;
   404→      rating?: number;
   405→      userRatingCount?: number;
   406→      businessStatus?: string;
   407→    }[];
   408→  };
   409→
   410→  return (data.places ?? []).map((p, i) => ({
   411→    id: p.id ?? `gpl_${i}`,
   412→    name: p.displayName?.text ?? "Sin nombre",
   413→    address: p.formattedAddress ?? "",
   414→    phone: p.nationalPhoneNumber ?? "",
   415→    website: p.websiteUri ?? "",
   416→    rating: p.rating ?? 0,
   417→    reviews: p.userRatingCount ?? 0,
   418→    status: p.businessStatus ?? "UNKNOWN",
   419→    source: "google" as const,
   420→  }));
   421→}
