   427→    res.status(401).json({ error: "No autenticado" });
   428→    return;
   429→  }
   430→
   431→  const {
   432→    query = "restaurante",
   433→    location = "Neuquén Capital",
   434→    maxResults = 20,
   435→  } = req.body as { query?: string; location?: string; maxResults?: number };
   436→
   437→  const [userConfig] = await db
